#include<cstdio>
#include<vector>
#include<algorithm>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline T Abs(const T&x){return x<0?-x:x;}
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e5+10;int n,TT,P[N];struct dt{int x,y;}a[N];
int Bit[N];inline void add(int p,int w){while(p<=n)Bit[p]=max(Bit[p],w),p+=(p&-p);}
inline int qry(int p){int mx=0;while(p)mx=max(mx,Bit[p]),p^=(p&-p);return mx;} 
std::vector<int> LIS[N];LL dp[N];const LL INF=0x3f3f3f3f3f3f3f3fll;
inline LL Dis(int x,int y){return Abs(1ll*(a[x].x-a[y].x)*(a[x].y-a[y].y));}
inline void Solve(std::vector<int> &g,std::vector<int> &f,int l,int r,int ql,int qr)
{
	if(l>r)return;int mid=(l+r)>>1,Mid=f[mid],qm=ql;LL res=dp[g[ql]]+Dis(g[ql],Mid);
	rep(ql+1,qr,i){LL x=dp[g[i]]+Dis(g[i],Mid);if(x<res)res=x,qm=i;} 
	dp[Mid]=min(dp[Mid],res); Solve(g,f,l,mid-1,qm,qr);Solve(g,f,mid+1,r,ql,qm);
}

std::vector<int> Qy[N<<2];
inline void mdy(int pos,std::vector<int> &g,int l,int r,int cur=1)
{
	if(a[g[l]].y<=a[pos].y&&g[r]<=pos){Qy[cur].push_back(pos);return;}
	if(a[g[r]].y>a[pos].y||g[l]>pos)return;
	int mid=(l+r)>>1;mdy(pos,g,l,mid,cur<<1);mdy(pos,g,mid+1,r,cur<<1|1);
}
inline void dfs(std::vector<int> &g,int l,int r,int cur=1)
{
	if(Qy[cur].size())
	{
		Solve(g,Qy[cur],0,Qy[cur].size()-1,l,r);
		std::vector<int> t;Qy[cur].swap(t);
	}
	if(l==r)return;int mid=(l+r)>>1;
	dfs(g,l,mid,cur<<1);dfs(g,mid+1,r,cur<<1|1);
}
int main()
{
	n=read();TT=read();rep(1,n,i){a[i].x=read();P[i]=a[i].y=read();}std::sort(P+1,P+n+1);
	std::sort(a+1,a+n+1,[&](const dt&x,const dt&y){return x.x<y.x;});
	rep(1,n,i){int x=std::lower_bound(P+1,P+n+1,a[i].y)-P,w=qry(x)+1;add(x,w);LIS[w].push_back(i);} 
	memset(dp,0x3f,sizeof(dp));for(int i:LIS[1])dp[i]=1ll*a[i].x*a[i].y;
	int i=2;for(;LIS[i].size();++i)
	{
		for(int j:LIS[i])mdy(j,LIS[i-1],0,LIS[i-1].size()-1);
		dfs(LIS[i-1],0,LIS[i-1].size()-1);
	}
	LL ans=INF;for(int v:LIS[i-1])ans=min(ans,dp[v]+1ll*(TT-a[v].x)*(TT-a[v].y));
	printf("%lld\n",ans);return 0;
}
